#### UI/FloatingIndicator.swift
```swift
import AppKit
import SwiftUI

@MainActor
final class FloatingIndicatorController {
    private var window: NSWindow?
    private let appModel: AppModel
    private let viewModel = IndicatorViewModel()

    // Coalesce rapid show/hide calls so AppKit never sees two visibility
    // changes within the same run loop turn. Without this, rapid hotkey
    // presses trigger reentrant constraint updates → _crashOnException.
    private var pendingVisible: Bool? = nil
    private var visibilityScheduled = false

    /// Base width when no partial transcript is shown.
    private static let compactWidth: CGFloat = 160
    /// Expanded width when partial transcript text is visible.
    private static let expandedWidth: CGFloat = 300

    init(appModel: AppModel) {
        self.appModel = appModel
    }

    func showRecording(duration: Duration, level: Float, partialTranscript: String? = nil) {
        let totalSeconds = Int(duration.components.seconds)
        let minutes = totalSeconds / 60
        let seconds = totalSeconds % 60
        viewModel.icon = "🎤"
        viewModel.text = "\(minutes):\(String(format: "%02d", seconds))"
        viewModel.isAnimating = true
        viewModel.partialTranscript = Self.truncatedPartial(partialTranscript)
        resizeWindowIfNeeded()
        scheduleVisibility(true)
    }

    func showTranscribing() {
        viewModel.icon = "⟳"
        viewModel.text = "Transcribing..."
        viewModel.isAnimating = false
        viewModel.partialTranscript = nil
        resizeWindowIfNeeded()
        scheduleVisibility(true)
    }

    func showLoading(elapsed: Int) {
        viewModel.icon = "⏳"
        viewModel.text = "Loading model... \(elapsed)s"
        viewModel.isAnimating = false
        viewModel.partialTranscript = nil
        resizeWindowIfNeeded()
        scheduleVisibility(true)
    }

    func hide() {
        viewModel.partialTranscript = nil
        scheduleVisibility(false)
    }
```

