// MARK: - Event Handlers

extension DictationController {

    // MARK: - Hotkey Event Mapping

    func handleHotkeyEvent(_ event: HotkeyEvent) async {
        switch event {
        case .hotkeyDown(let instant):
            await handle(.hotkeyDown(instant))
        case .hotkeyUp(let instant):
            await handle(.hotkeyUp(instant))
        case .escapeDown(let instant):
            await handle(.escapeDown(instant))
        case .tapDisabledByTimeout:
            await handle(.tapDisabledByTimeout)
        }
    }

    // MARK: - State Transitions

    func handleHotkeyDown(at instant: ContinuousClock.Instant) async {
        // p02: controller received hotkey event. Stamped before any work so it
        // captures the actual actor-hop latency from the tap thread.
        let controllerReceivedAt = ContinuousClock.Instant.now

        switch state {
        case .idle:
            let micOK = await MainActor.run { permissionsService.microphoneGranted }
            let axOK = await MainActor.run { permissionsService.accessibilityGranted }

            if !micOK {
                let granted = await permissionsService.requestMicrophoneAccess()
