import Foundation

/// Detects and strips self-correction patterns from transcription text.
///
/// Users correct ASR errors by saying "*Claude" (star-correction) after a
/// misrecognised word. This stripper detects the `*word` pattern, removes
/// the asterisk prefix so the cleaned word remains in the output, and
/// returns the list of corrections found for logging and mining.
///
/// Must run BEFORE `stripTranscriptionArtifacts()` because that method
/// blindly removes all `*` characters, destroying the correction signal.
enum SelfCorrectionStripper {

    /// A single self-correction detected in the transcription text.
    struct Correction: Sendable, Equatable, Codable {
        /// The raw pattern matched (e.g. "*Claude").
        let raw: String
        /// The intended word(s) extracted from the pattern (e.g. "Claude").
        let intended: String
    }

    /// Result of stripping self-corrections from text.
    struct Result: Sendable, Equatable {
        /// Text with correction markers removed (e.g. "*Claude" -> "Claude").
        let text: String
        /// All corrections detected, in order of appearance.
        let corrections: [Correction]
    }

    // Star-correction pattern: `*word` or `*word word`
    //
    // Group 1: optional leading whitespace (preserved in replacement)
    // Group 2: the intended word(s) -- 1 to 3 words after `*`
    //
    // The `*` must be at the start of the string or after whitespace to avoid
    // matching mid-expression asterisks (e.g. `2*3`, `bold*text*`).
    // Multi-word capture is capped at 3 words to avoid swallowing whole sentences
    // (e.g. "*Claude Code is great" -> captures "Claude Code is", not more).
    private static let starPattern: NSRegularExpression = {
        // (^|\s) -- leading boundary (captured so we can preserve the space)
        // \*\s*  -- the star plus optional space
        // (\w+(?:[\s-]\w+){0,2}) -- 1-3 words sepa
