```swift
if let tsid {
    await TimingSession.shared.stamp(id: tsid, phase: .p13a_reconcile_start)
}
// ... feed remaining samples ...
if let tsid {
    await TimingSession.shared.stamp(id: tsid, phase: .p13a_reconcile_end)
    await TimingSession.shared.stamp(id: tsid, phase: .p13b_inflight_wait_start)
}
