func requestRemove(_ entry: VocabEntry) {
    let linked = /* compute linked rules */
    pendingDelete = PendingDelete(entry: entry, linkedRules: linked)
}

// clearPendingDelete becomes:
func clearPendingDelete() { pendingDelete = nil }

// performRemove reads from the struct:
func performRemove(alsoRemoveLinked: Bool) {
    guard let pd = pendingDelete else { return }
    // use pd.entry, pd.linkedRules
    pendingDelete = nil
