    var miningBatchSize: Int {
        didSet {
            guard miningBatchSize != oldValue else { return }
            storage.defaults.set(miningBatchSize, forKey: SettingsKeys.miningBatchSize)
            storage.logSettingChange(key: SettingsKeys.miningBatchSize, value: String(miningBatchSize))
        }
    }

    private let storage: SettingsStorage

    init(storage: SettingsStorage) {
        self.storage = storage
        self.localMiningEnabled = storage.defaults.object(forKey: SettingsKeys.localMiningEnabled) as? Bool ?? true
        self.miningBatchSize = storage.defaults.object(forKey: SettingsKeys.miningBatchSize) as? Int ?? 5
    }

    func resetAfterDeleteAllData() {
        localMiningEnabled = true
        miningBatchSize = 5
    }
}

