import Foundation
import TunedVoiceKit

/// A vocabulary term with a CTC boost weight for FluidAudio keyword boosting.
///
/// Weight controls the CTC log-probability threshold for keyword detection:
/// higher weight = more aggressive detection (lower threshold).
///
/// **Scale (v2, 2026-04-19)**: weights are now on a 0–2.0 multiplier scale.
/// FluidAudio's base CBW is ~3.0; a weight of 1.0 produces an effective CBW of
/// 3.0 (neutral), 2.0 produces 6.0 (strong). The old 0–25 scale was 10x too
/// high (effective CBW 30+, killing recognition confidence).
///
/// Weight sources:
/// - User-defined custom words: ``defaultUserWeight`` (1.0)
/// - Text replacement targets: ``defaultUserWeight`` (1.0)
/// - Mined terms: 1.0–2.0 (severity-based, see `VocabularyMiner.weightBase`/`weightCap`)
///
/// See `apps/mac_os/docs/transcription-pipeline.md` for full pipeline context.
struct WeightedVocabularyItem: Equatable {
    /// Default CTC boost weight for user-defined vocabulary and text replacement targets.
    /// On the 0–2.0 multiplier scale: 1.0 is neutral (effective CBW ≈ FluidAudio's base).
    static let defaultUserWeight: Double = 1.0

    /// Maximum CTC boost weight the UI will allow a user to set, and the upper
    /// bound used by `VocabularyMiner` when deriving severity-based weights.
    /// On the 0–2.0 multiplier scale: 2.0 produces effective CBW ≈ 6.0 (strong boost).
    /// See `work/research/vocab-controls-745-editable-weight.md`.
    static let weightCap: Double = 2.0

    /// Minimum editable weight. `0.0` keeps the term in the list but disables
    /// boosting (FluidAudio ignores zero-weight entries). See issue #745.
    static let weightFloor: Double = 0.0

    let text: String
    let weight: Double

    init(text: String, weight: Double = Self.defaultUserWeight) {
        self.text = text
        self.weight = weight
    }
}

