import Foundation

/// Loads and manages vocabulary packs from the app resource bundle.
///
/// Packs are JSON files in `Resources/vocabulary_packs/`. Users toggle packs
/// on/off via Settings; enabled state persists in UserDefaults.
enum VocabularyPackStore {
    private static let enabledKey = "TunedVoice.enabledVocabularyPacks"
    private static let subdirectory = "vocabulary_packs"

    /// Override for test isolation. When set, packs load from this directory.
    internal static var _directoryOverride: URL? {
        didSet { _cachedPacks = nil }
    }

    /// Cached packs — loaded once from disk, cleared on test override change.
    private static var _cachedPacks: [VocabularyPack]?

    // MARK: - Loading

    /// All available vocabulary packs from the resource bundle (cached after first load).
    static func availablePacks() -> [VocabularyPack] {
        if let cached = _cachedPacks { return cached }
        let directory: URL
        if let override = _directoryOverride {
            directory = override
        } else {
            let bundle = SafeResourceBundle.resolve()
            guard let url = bundle.resourceURL?.appendingPathComponent(subdirectory) ??
                  bundle.url(forResource: subdirectory, withExtension: nil) else {
                return []
            }
            directory = url
        }

        guard let contents = try? FileManager.default.contentsOfDirectory(
            at: directory, includingPropertiesForKeys: nil
        ) else { return [] }

        let decoder = JSONDecoder()
        let packs: [VocabularyPack] = contents
            .filter { $0.pathExtension == "json" }
            .compactMap { url in
                guard let data = try? Data(contentsOf: url) else { return nil }
                return try? decoder.decode(VocabularyPack.self, from: data)
            }
            .sorted { $0.name < $1.name }
        _cachedPacks = packs
