```swift
import Foundation

/// Accumulates dictation transcripts after each dictation and tracks when
/// a batch LLM mining run should be triggered.
///
/// The actor persists its queue to disk so transcripts are not lost if the
/// app quits before the batch threshold is reached.
///
/// ## Thread safety
///
/// All mutations happen on the actor's executor. Callers that need
/// `pendingCount` on the MainActor should use `await accumulator.pendingCount`.
actor MiningAccumulator {

    // MARK: - Stored entry type

    struct PendingEntry: Codable, Sendable {
        let text: String
        let timestamp: Date
    }

    // MARK: - State

    private var pending: [PendingEntry] = []
    private let persistenceURL: URL

    // MARK: - Init

    init(persistenceURL: URL? = nil) {
        let url = persistenceURL ?? Self.defaultPersistenceURL()
        self.persistenceURL = url
        // Load persisted queue synchronously during init (actor isolated, safe).
        if let loaded = Self.loadFromDisk(at: url) {
            self.pending = loaded
            Log.mining.info(
                "MiningAccumulator: loaded \(loaded.count) pending entries from disk at \(url.lastPathComponent)"
            )
        } else {
            Log.mining.info("MiningAccumulator: starting with empty queue (no persisted data)")
        }
    }

    // MARK: - Public API

    /// Number of transcripts waiting to be processed.
    var pendingCount: Int { pending.count }

    /// Returns true when `pendingCount >= threshold` and `threshold > 0`.
    func shouldTriggerBatch(threshold: Int) -> Bool {
        guard threshold > 0 else { return false }
        return pending.count >= threshold
    }

    /// Appends a dictation transcript to the pending queue and saves to disk.
    ///
    /// - Parameter text: The processed transcript text from a completed dictation.
    /// - Parameter timestamp: When the dictation finished. Defaults to `Date()`.
```

