import Darwin
import Foundation

/// Checks whether the system is in a suitable state for running the local
/// LLM mining batch (which loads a ~5 GB Qwen3.5-9B model into unified memory).
///
/// This is a value-type utility: create one on-demand, call `canMine()`, and
/// discard. All checks are synchronous and should complete in microseconds.
struct SystemConditionChecker {

    // MARK: - Configuration

    /// Minimum free memory required before spawning the local LLM.
    /// The Qwen3.5-9B 4-bit quantization uses ~5 GB; 6 GB gives ~1 GB headroom.
    static let requiredFreeMemoryBytes: UInt64 = 6 * 1_024 * 1_024 * 1_024

    // MARK: - Result type

    enum CheckResult: CustomStringConvertible {
        case canMine
        case skip(reason: SkipReason)

        var canMine: Bool {
            if case .canMine = self { return true }
            return false
        }

        var description: String {
            switch self {
            case .canMine:
                return "canMine"
            case .skip(let reason):
                return "skip(\(reason))"
            }
        }
    }

    enum SkipReason: CustomStringConvertible {
        case thermalPressure(state: String)
        case insufficientMemory(availableMB: Int)
        case currentlyRecording

        var description: String {
            switch self {
            case .thermalPressure(let state):
                return "thermalPressure(state=\(state))"
            case .insufficientMemory(let mb):
                return "insufficientMemory(available=\(mb)MB)"
            case .currentlyRecording:
                return "currentlyRecording"
            }
        }
    }

    // MARK: - API

    /// Returns `.canMine` if all conditions are met, `.skip` otherwise.
    ///
    /// - Parameter isRecording: Pass `true` if a dictation session is active.
    ///   Obtain this from `RecordingManager.isRecording` on the MainActor before
