Mirror the enumeration pattern from diskUsage() and performCleanup(), applying the same filters and using the existing static helpers:

```swift
func audioRecordingURLs() -> [URL] {
    let dir = recordingsDirectoryURL()
    guard let enumerator = FileManager.default.enumerator(
        at: dir,
        includingPropertiesForKeys: [.isRegularFileKey, .contentModificationDateKey],
        options: [.skipsHiddenFiles, .skipsSubdirectoryDescendants]
    ) else { return [] }

    var files: [(url: URL, date: Date)] = []
    for case let fileURL as URL in enumerator {
        guard let values = try? fileURL.resourceValues(
                forKeys: [.isRegularFileKey, .contentModificationDateKey]),
              values.isRegularFile == true else { continue }
        guard Self.isTunedVoiceRecording(fileURL) else { continue }
        guard !fileURL.lastPathComponent.hasSuffix(".diagnostics.json") else { continue }
        let date = Self.parseDate(from: fileURL.lastPathComponent)
            ?? values.contentModificationDate
            ?? Date.distantPast
        files.append((url: fileURL, date: date))
    }
    return files.sorted { $0.date > $1.date }.map(\.url)
}
```

Key decisions that match existing patterns:

- Self.isTunedVoiceRecording(fileURL) is the canonical filter for all TunedVoice-owned files, used identically in diskUsage(). Do not inline an extension check — use the static method.
- The .diagnostics.json exclusion follows performCleanup()'s guard, keeping this method aligned with the principle that diagnostics have a separate lifecycle managed by diagnosticsFileURLs().
