import Foundation

/// Available hotkey presets for triggering dictation.
enum HotkeyOption: String, CaseIterable, Sendable, Identifiable {
    case fnKey = "fn"
    case rightOption = "rightOption"
    case rightCommand = "rightCommand"
    case controlKey = "control"
    case optionSpace = "optionSpace"

    var id: String { rawValue }

    var displayName: String {
        switch self {
        case .fnKey: "Fn (Globe)"
        case .rightOption: "Right Option ⌥"
        case .rightCommand: "Right Command ⌘"
        case .controlKey: "Control ⌃"
        case .optionSpace: "Option + Space"
        }
    }

    var shortLabel: String {
        switch self {
        case .fnKey: "Fn"
        case .rightOption: "R⌥"
        case .rightCommand: "R⌘"
        case .controlKey: "⌃"
        case .optionSpace: "⌥Space"
        }
    }

    /// Whether this hotkey uses only modifier keys (flagsChanged events only)
    /// vs a modifier+key combo (needs keyDown/keyUp events too).
    var isModifierOnly: Bool {
        switch self {
        case .fnKey, .rightOption, .rightCommand, .controlKey: true
        case .optionSpace: false
        }
    }
}

/// Whether the user wants hold-to-record or toggle (double-press) mode.
enum HotkeyMode: String, CaseIterable, Sendable, Identifiable {
    case hold = "hold"
    case toggle = "toggle"

    var id: String { rawValue }

    var displayName: String {
        switch self {
        case .hold: "Hold to Record"
        case .toggle: "Double-Press to Toggle"
        }
    }

    var description: String {
        switch self {
        case .hold: "Hold the key to record, release to stop"
        case .toggle: "Press twice quickly to start/stop recording"
        }
    }
}

```

